CREATE TABLE onboardings (onboarding_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE, role user_role NOT NULL, status VARCHAR(50) NOT NULL DEFAULT 'draft', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE document_type_definitions (document_type VARCHAR(50) PRIMARY KEY, applicable_role user_role NOT NULL, applicable_country CHAR(2) NOT NULL DEFAULT 'IN', is_required BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE onboarding_documents (document_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), onboarding_id UUID NOT NULL REFERENCES onboardings(onboarding_id) ON DELETE CASCADE, document_type VARCHAR(50) NOT NULL REFERENCES document_type_definitions(document_type), s3_key VARCHAR(512), upload_status VARCHAR(50) NOT NULL DEFAULT 'pending', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
